#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

// sample previous uFrame
ret = texture( sampler_main, vUv);

vec2 uvm=vUv+uTime;

// darken the color channels at different rates
ret *= vec3(.9,.9,9.0)+.15*tex2d(sampler_noise_hq, vUv);
ret-=.002;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//initial textures:
//1. Main image
     vec3 base=texture(sampler_main, vUv);
//2. High quality noise sampler
     vec3 hinoise=texture(sampler_noise_hq, vUv);

//declaring modifying vars:
//1. Perspective UV value
     vec2 uvp=vUv;
     uvp.y*=.38;
//2. Main grid texture UV value
     vec2 uvbm = vUv;
     uvbm.x*=tex2d(sampler_noise_hq, vUv.x-.5);
     uvbm.y*=tex2d(sampler_noise_hq, vUv.y-.5);
     vec2 uvpm = uvp;
     uvpm.x*=tex2d(sampler_noise_hq, uvp.x-.5+q2);
     uvpm.y*=tex2d(sampler_noise_hq, uvp.y-.5+q1);

//3. Blur values
     vec3 blpi=GetBlur1(uvp);
     vec3 blpii=GetBlur2(uvp);
     vec3 blpiii= GetBlur3(uvp);
     vec3 blmi=GetBlur1(vUv);
     vec3 blmii=GetBlur2(vUv);
     vec3 blmiii=GetBlur3(vUv);

//Perspective modified samplers
//1. Perspective Main
     vec3 pret=texture(sampler_main, uvp);

//final return values
vec3 tret=tex2d(sampler_main, uvpm);
vec3 fret=(.17*blpiii/(pret*blpiii)).x;
fret-=blmii*1.35;

ret=fret*tret*(1-tret*tret);
ret*=1-.5*fret*(1-4*ret);
ret=1-ret;
ret*=ret*lum(ret-blpii);
ret=1-ret;

  fragColor = ret;
}
